# Manual Dead Lettering in Celery
@app.task(bind=True, max_retries=3)
def process_complex_data(self, data):
    try:
        return heavy_processing(data)
    except Exception as exc:
        if self.request.retries >= self.max_retries:
            # Move to a separate 'failed' queue for human review
            send_to_dlq.apply_async(args=[data, str(exc)], queue='dlq')
        raise self.retry(exc=exc)
```

